export type NikaAnimId =
  | 'anim/agent'
  | 'anim/butterfly'
  | 'anim/exec'
  | 'anim/infer'
  | 'anim/invoke'
  | 'anim/loading'

export interface NikaAnimDef {
  /** the dot-matrix figure (src/fx/dotmatrix/patterns.ts) */
  pattern: 'sample' | 'scanline' | 'roundtrip' | 'orbit' | 'wave' | 'emerge'
  /** plays forward then back (request/response · wing-beat) */
  alternate?: boolean
  /** the verb hue CSS var — live-run surfaces only (BRAND ink law) */
  hue?: string
  label: string
}

export const NK_ANIMS: Record<NikaAnimId, NikaAnimDef> = {
  'anim/agent': { pattern: 'orbit', hue: 'var(--verb-agent)', label: 'Agent · orbit' },
  'anim/butterfly': { pattern: 'emerge', alternate: true, label: 'The butterfly beats' },
  'anim/exec': { pattern: 'scanline', hue: 'var(--verb-exec)', label: 'Exec · scanline' },
  'anim/infer': { pattern: 'sample', hue: 'var(--verb-infer)', label: 'Infer · sampling' },
  'anim/invoke': { pattern: 'roundtrip', alternate: true, hue: 'var(--verb-invoke)', label: 'Invoke · roundtrip' },
  'anim/loading': { pattern: 'wave', label: 'Loading · wave' },
}
